CREATE OR REPLACE FUNCTION log_player_name_changes() 
RETURNS trigger AS $BODY$ 
BEGIN 
    IF NEW.player_name <> OLD.player_name THEN 
        INSERT INTO player_audits(player_id, old_player_name, changed_on) 
        VALUES(OLD.id, OLD.player_name, now()); 
    END IF; 
    RETURN NEW; 
END; 
$BODY$ 
LANGUAGE plpgsql;

CREATE TRIGGER tr_change_playername 
AFTER UPDATE OF player_name ON player 
FOR EACH ROW 
EXECUTE PROCEDURE log_player_name_changes()

CREATE OR REPLACE FUNCTION pg_try_advisory_xact_lock_with_timeout(key bigint)
RETURNS boolean AS $$
DECLARE
    original_timeout text;
    lock_acquired boolean;
BEGIN
    SHOW lock_timeout INTO original_timeout;
    SET LOCAL lock_timeout = '1s';

    BEGIN
        PERFORM pg_advisory_xact_lock(key);
        lock_acquired := true;
    EXCEPTION
        WHEN lock_not_available THEN
            lock_acquired := false;
        WHEN deadlock_detected THEN
            lock_acquired := false;
    END;

    EXECUTE format('SET LOCAL lock_timeout = %L', original_timeout);

    RETURN lock_acquired;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION total_loans()
    RETURNS TRIGGER
    AS $$
    DECLARE
        v_account_id bigint;
    BEGIN
        -- Determine which account_id to update
        IF TG_OP = 'DELETE' THEN
            v_account_id := OLD.account_id;
        ELSE
            v_account_id := NEW.account_id;
        END IF;

        -- Update the summary for the affected account
        UPDATE loan_summary
        SET total_loan_count = COALESCE(
            (SELECT COUNT(*) 
             FROM loan 
             WHERE loan.account_id = v_account_id 
               AND loan.status = 'A'), 
            0
        )
        WHERE account_id = v_account_id;

        -- If UPDATE and account_id changed, update old account too
        IF TG_OP = 'UPDATE' AND OLD.account_id IS DISTINCT FROM NEW.account_id THEN
            UPDATE loan_summary
            SET total_loan_count = COALESCE(
                (SELECT COUNT(*) 
                 FROM loan 
                 WHERE loan.account_id = OLD.account_id 
                   AND loan.status = 'A'), 
                0
            )
            WHERE account_id = OLD.account_id;
        END IF;

        -- Return appropriate value based on operation
        IF TG_OP = 'DELETE' THEN
            RETURN OLD;
        ELSE
            RETURN NEW;
        END IF;
    END;
    $$ LANGUAGE plpgsql

