CREATE OR REPLACE FUNCTION lcp_token_iterate(_state TEXT, value TEXT) RETURNS TEXT AS $$
DECLARE
    state_tokens TEXT[];
    value_tokens TEXT[];
    i INTEGER;
    result TEXT;
BEGIN
    -- Handle NULL cases
    IF _state IS NULL THEN
        RETURN value;
    END IF;
    IF value IS NULL THEN
        RETURN _state;
    END IF;

    -- Split both strings by '#' delimiter
    state_tokens := string_to_array(_state, '#');
    value_tokens := string_to_array(value, '#');

    result := '';

    -- Compare tokens one by one
    FOR i IN 1..LEAST(array_length(state_tokens, 1), array_length(value_tokens, 1)) LOOP
        IF state_tokens[i] = value_tokens[i] THEN
            -- Add token with delimiter (except for first token, no leading '#')
            IF result = '' THEN
                result := state_tokens[i];
            ELSE
                result := result || '#' || state_tokens[i];
            END IF;
        ELSE
            -- Tokens don't match, stop here
            EXIT;
        END IF;
    END LOOP;

    -- Return result with trailing '#' if we matched at least one token and there are more tokens
    -- Actually, we need to add '#' if the next step would continue, but since we exit on mismatch,
    -- we need to check if we should add trailing '#' for partial match indication
    -- But per requirements, we only want complete matching tokens, so no trailing '#'

    RETURN result;
END;
$$ LANGUAGE plpgsql;

DO $$
BEGIN
    CREATE AGGREGATE lcp_token(TEXT) (
        SFUNC = lcp_token_iterate,
        STYPE = TEXT
    );
EXCEPTION
    WHEN sqlstate '42723' THEN
        -- Aggregate already exists, drop and recreate
        DROP AGGREGATE lcp_token(TEXT);
        CREATE AGGREGATE lcp_token(TEXT) (
            SFUNC = lcp_token_iterate,
            STYPE = TEXT
        );
END $$;

