-- First create a type (can be done once)
CREATE TYPE my_row_type AS (
    id_column BIGINT,
    decimal_column DECIMAL(28,8),
    nvarchar_column VARCHAR(30)
);

-- Then query with ordinality
SELECT r.*, t.ordinality - 1 AS array_index
FROM jsonb_populate_recordset(
    NULL::my_row_type,
    '[
        {"id_column": 1234, "decimal_column": 12.34, "nvarchar_column": "asdf"},
        {"id_column": 5678, "decimal_column": 56.78, "nvarchar_column": "fdsa"}
    ]'::jsonb
) WITH ORDINALITY AS r(id_column, decimal_column, nvarchar_column, ordinality)
CROSS JOIN LATERAL (SELECT r.ordinality AS ordinality) AS t(ordinality)

DO $$
DECLARE
    v_id bigint;
    v_date date;
    db_update_cursor CURSOR FOR
        SELECT id, date
        FROM laboratory
        ORDER BY id, date
        LIMIT 2;
BEGIN
    -- Create temp table
    CREATE TEMP TABLE IF NOT EXISTS destinationTable (
        testRow jsonb
    );

    OPEN db_update_cursor;
    FETCH NEXT FROM db_update_cursor INTO v_id, v_date;
    WHILE FOUND LOOP
        INSERT INTO destinationTable(testRow)
        VALUES (jsonb_build_object('id', v_id, 'date', v_date));

        FETCH NEXT FROM db_update_cursor INTO v_id, v_date;
    END LOOP;

    CLOSE db_update_cursor;
END $$

DO $$
DECLARE
    batch_size INT := 10000;
    rows_inserted INT;
    total_inserted INT := 0;
BEGIN
    LOOP
        -- Insert only players that don't already exist in player_stats
        INSERT INTO player_stats (player_id, match_id, goals, assists, yellow_cards, red_cards, minutes_played)
        SELECT t.player_id, t.match_id, t.goals, t.assists, t.yellow_cards, t.red_cards, t.minutes_played
        FROM player_stats_temp t
        WHERE NOT EXISTS (
            SELECT 1 FROM player_stats p WHERE p.player_id = t.player_id
        )
        LIMIT batch_size;

        GET DIAGNOSTICS rows_inserted = ROW_COUNT;
        total_inserted := total_inserted + rows_inserted;

        -- Exit when no more rows to insert
        EXIT WHEN rows_inserted = 0;

        RAISE NOTICE 'Inserted % rows, total: %', rows_inserted, total_inserted;
    END LOOP;

    RAISE NOTICE 'Batch insert complete. Total rows inserted: %', total_inserted;
END $$

