CREATE OR REPLACE FUNCTION FIND_TEST_TABLE_COLUMN(
    IN_COLUMN1 VARCHAR,
    IN_COLUMN2 VARCHAR,
    IN_COLUMN3 VARCHAR,
    IN_COLUMN4 VARCHAR,
    IN_REQUESTED_COLUMN VARCHAR
) RETURNS VARCHAR AS $$
DECLARE
    C_TEST_TABLE_REC RECORD;
    RESULT VARCHAR;
    query TEXT;
BEGIN
    query := 'SELECT * FROM test_table WHERE column1 = $1 AND column2 = $2 AND column3 = $3';

    IF IN_COLUMN4 IS NOT NULL THEN
         query := query || ' AND column4 = $4';
    END IF;

    query := query || ' LIMIT 1';

    IF IN_COLUMN4 IS NULL THEN
         EXECUTE query INTO C_TEST_TABLE_REC USING IN_COLUMN1, IN_COLUMN2, IN_COLUMN3;
    ELSE
         EXECUTE query INTO C_TEST_TABLE_REC USING IN_COLUMN1, IN_COLUMN2, IN_COLUMN3, IN_COLUMN4;
    END IF;

    -- Check if record was found
    IF C_TEST_TABLE_REC IS NULL THEN
        RETURN NULL;
    END IF;

    -- Use correct record variable name (C_TEST_TABLE_REC, not C_TEST_TABLE)
    CASE UPPER(IN_REQUESTED_COLUMN)
        WHEN 'COLUMN1' THEN RESULT := C_TEST_TABLE_REC.column1;
        WHEN 'COLUMN2' THEN RESULT := C_TEST_TABLE_REC.column2;
        WHEN 'COLUMN3' THEN RESULT := C_TEST_TABLE_REC.column3;
        WHEN 'COLUMN4' THEN RESULT := C_TEST_TABLE_REC.column4;
        ELSE RESULT := NULL;
    END CASE;

    RETURN RESULT;
END;
$$ LANGUAGE plpgsql
